<?php
namespace App\Services\Notifications;use App\Models\{Hotel,HotelIntegration};use Illuminate\Http\Request;
class FcmSettings{public function save(Request$r,Hotel$hotel):HotelIntegration{$data=$r->validate(['project_id'=>'required|string|max:150','client_email'=>'required|email|max:255','private_key'=>'nullable|string|max:10000','token_uri'=>'required|url|max:500','api_key'=>'nullable|string|max:255','messaging_sender_id'=>'nullable|string|max:100','android_app_id'=>'nullable|string|max:255','ios_app_id'=>'nullable|string|max:255','active'=>'required|boolean']);$integration=HotelIntegration::firstOrNew(['hotel_id'=>$hotel->id,'type'=>'fcm']);$current=$integration->configuration??[];if(blank($data['private_key'])&&blank($current['private_key']??null))abort(422,'A Firebase private key is required.');if(blank($data['private_key']))$data['private_key']=$current['private_key'];else$data['private_key']=str_replace('\\n',"\n",trim($data['private_key']));$integration->fill(['active'=>$data['active'],'configuration'=>$data,'connection_status'=>'untested','last_error'=>null,'last_tested_at'=>null])->save();return$integration;}public function test(Hotel$hotel,FcmClient$client):HotelIntegration{$integration=HotelIntegration::where('hotel_id',$hotel->id)->where('type','fcm')->firstOrFail();try{$client->test($hotel);$integration->update(['connection_status'=>'connected','last_error'=>null,'last_tested_at'=>now()]);}catch(\Throwable$e){$integration->update(['connection_status'=>'failed','last_error'=>$e->getMessage(),'last_tested_at'=>now()]);throw$e;}return$integration;}}
